    66→fn providers_path(cards_dir: &Path) -> PathBuf {
    67→    cards_dir.join("providers.json")
    68→}
    69→
    70→pub fn read_providers(cards_dir: &Path) -> anyhow::Result<ProvidersFile> {
    71→    let p = providers_path(cards_dir);
    72→    if !p.exists() {
    73→        return Ok(ProvidersFile::default());
    74→    }
    75→    let bytes = fs::read(p)?;
    76→    let pf: ProvidersFile = serde_json::from_slice(&bytes)?;
    77→    for (name, provider) in &pf.providers {
    78→        validate_provider(name, provider)?;
    79→    }
    80→    Ok(pf)
    81→}
    82→
    83→pub fn write_providers(cards_dir: &Path, pf: &ProvidersFile) -> anyhow::Result<()> {
    84→    for (name, provider) in &pf.providers {
    85→        validate_provider(name, provider)?;
    86→    }
    87→    let bytes = serde_json::to_vec_pretty(pf)?;
    88→
    89→    let target = providers_path(cards_dir);
    90→    let tmp = target.with_extension("json.tmp");
    91→
    92→    fs::write(&tmp, &bytes)?;
    93→    fs::rename(&tmp, &target)?;
    94→
    95→    Ok(())
    96→}
