   215→pub fn set_provider_cooldown(
   216→    cards_dir: &Path,
   217→    provider: &str,
   218→    cooldown_s: i64,
   219→) -> anyhow::Result<()> {
   220→    let mut pf = read_providers(cards_dir)?;
   221→    let now = Utc::now().timestamp();
   222→    if let Some(p) = pf.providers.get_mut(provider) {
   223→        p.cooldown_until_epoch_s = Some(now + cooldown_s);
   224→    }
   225→    write_providers(cards_dir, &pf)?;
   226→    Ok(())
   227→}
