    51→/// Provider implementation for Claude Code OAuth quota monitoring.
    52→pub struct ClaudeProvider;
    53→
    54→impl ClaudeProvider {
    55→    pub fn new() -> Self {
    56→        Self
    57→    }
    58→
    59→    /// Path to the Claude Code credentials file: `~/.claude/.credentials.json`.
    60→    fn credentials_path() -> Option<PathBuf> {
    61→        dirs::home_dir().map(|h| h.join(".claude").join(".credentials.json"))
    62→    }
    63→
    64→    /// Read and parse credentials — tries file first, then macOS Keychain.
    65→    ///
    66→    /// Keychain JSON shape: `{"claudeAiOauth":{"accessToken":"...","refreshToken":"..."}}`
    67→    /// File JSON shape:     `{"access_token":"...","refresh_token":"..."}`
    68→    fn read_credentials() -> anyhow::Result<ClaudeCredentials> {
    69→        // Try file first.
    70→        if let Some(path) = Self::credentials_path() {
    71→            if path.exists() {
    72→                let json = std::fs::read_to_string(&path).with_context(|| {
    73→                    format!("cannot read Claude credentials: {}", path.display())
    74→                })?;
    75→                return serde_json::from_str(&json).with_context(|| {
    76→                    format!("malformed Claude credentials at {}", path.display())
    77→                });
    78→            }
    79→        }
    80→        // Fall back to macOS Keychain.
    81→        #[cfg(target_os = "macos")]
    82→        {
    83→            if let Ok(raw) = Self::read_keychain_credentials() {
    84→                return Ok(raw);
    85→            }
    86→        }
    87→        anyhow::bail!("no Claude credentials found (checked file and Keychain)")
    88→    }
    89→
    90→    /// Extract credentials from macOS Keychain entry `Claude Code-credentials`.
    91→    ///
    92→    /// The Keychain stores JSON as `{"claudeAiOauth":{"accessToken":"...","refreshToken":"..."}}`.
    93→    #[cfg(target_os = "macos")]
    94→    fn read_keychain_credentials() -> anyhow::Result<ClaudeCredentials> {
    95→        let output = std::process::Command::new("security")
    96→            .args([
    97→                "find-generic-password",
    98→                "-s",
    99→                "Claude Code-credentials",
   100→                "-w",
   101→            ])
   102→            .output()
   103→            .context("failed to run `security` CLI")?;
   104→        anyhow::ensure!(output.status.success(), "Keychain lookup failed");
   105→        let raw = String::from_utf8(output.stdout).context("Keychain output not UTF-8")?;
   106→        let raw = raw.trim();
   107→        // Try flat shape first (access_token), then wrapped claudeAiOauth shape.
   108→        if let Ok(c) = serde_json::from_str::<ClaudeCredentials>(raw) {
   109→            return Ok(c);
   110→        }
   111→        // Wrapped shape: {"claudeAiOauth": {"accessToken": "...", "refreshToken": "...", "expiresAt": <epoch_ms>}}
   112→        // expiresAt is epoch-milliseconds (u64), not an ISO string.
   113→        #[derive(serde::Deserialize)]
   114→        struct KeychainInner {
   115→            #[serde(rename = "accessToken")]
   116→            access_token: String,
   117→            #[serde(rename = "refreshToken", default)]
   118→            refresh_token: Option<String>,
   119→            /// Epoch milliseconds — convert to ISO 8601 for the rest of the provider code.
   120→            #[serde(rename = "expiresAt", default)]
   121→            expires_at_ms: Option<u64>,
   122→        }
   123→        #[derive(serde::Deserialize)]
   124→        struct KeychainWrapper {
   125→            #[serde(rename = "claudeAiOauth")]
   126→            claude_ai_oauth: KeychainInner,
   127→        }
   128→        let w: KeychainWrapper =
   129→            serde_json::from_str(raw).context("unrecognised Keychain JSON shape")?;
   130→        // Convert epoch_ms → ISO 8601 string so the expiry check in fetch() works.
   131→        let expires_at = w.claude_ai_oauth.expires_at_ms.and_then(|ms| {
   132→            let secs = (ms / 1000) as i64;
   133→            chrono::DateTime::<chrono::Utc>::from_timestamp(secs, 0).map(|dt| dt.to_rfc3339())
   134→        });
   135→        Ok(ClaudeCredentials {
   136→            access_token: w.claude_ai_oauth.access_token,
   137→            refresh_token: w.claude_ai_oauth.refresh_token,
   138→            expires_at,
   139→        })
   140→    }
   141→
   142→    /// Check if Claude Code credentials exist on disk.
   143→    fn has_credentials_file() -> bool {
   144→        Self::credentials_path()
   145→            .map(|p| p.exists())
   146→            .unwrap_or(false)
