   187→            }
   188→        };
   189→
   190→        // Map five_hour.utilization → primary_pct (clamped to 0-100).
   191→        let primary_pct = usage
   192→            .five_hour
   193→            .as_ref()
   194→            .and_then(|w| w.utilization)
   195→            .map(|p| p.round().clamp(0.0, 100.0) as u8);
