631→    /// Fetch current quota/usage from the Codex OAuth API, falling back to
632→    /// JSON-RPC if credentials are missing or expired.
633→    ///
634→    /// Reads credentials, warns if refresh is stale, calls the usage endpoint,
635→    /// and maps the response to a `ProviderSnapshot`. If OAuth fails (no creds
636→    /// or token rejected), tries JSON-RPC via `codex app-server`. On failure,
637→    /// returns a snapshot with the `error` field set rather than propagating.
638→    async fn fetch(&self) -> anyhow::Result<ProviderSnapshot> {
639→        let creds = match Self::read_credentials() {
640→            Ok(c) => c,
641→            Err(_) => {
642→                // No OAuth credentials — try JSON-RPC, then PTY fallback.
643→                return Self::fetch_via_rpc_or_pty().await;
644→            }
645→        };
646→
647→        // Check if token refresh is stale (>8 days).
648→        let stale_warning = Self::check_refresh_staleness(&creds);
649→
650→        // Fetch usage data from the Codex OAuth API.
651→        let client = reqwest::Client::new();
652→        let resp = match client
653→            .get(USAGE_URL)
654→            .header("Authorization", format!("Bearer {}", creds.access_token))
655→            .send()
656→            .await
657→        {
658→            Ok(r) => r,
659→            Err(e) => {
660→                return Ok(ProviderSnapshot {
661→                    provider: "codex".into(),
662→                    display_name: "Codex CLI".into(),
663→                    primary_pct: None,
664→                    secondary_pct: None,
665→                    primary_label: Some("session".into()),
666→                    secondary_label: Some("weekly".into()),
667→                    tokens_used: None,
668→                    cost_usd: None,
669→                    reset_at: None,
670→                    source: "oauth".into(),
671→                    error: Some(format!("HTTP request failed: {e}")),
672→                });
673→            }
674→        };
675→
676→        let status = resp.status();
677→        if status == reqwest::StatusCode::UNAUTHORIZED || status == reqwest::StatusCode::FORBIDDEN {
678→            // Token rejected — try JSON-RPC, then PTY fallback.
679→            return Self::fetch_via_rpc_or_pty().await;
680→        }
681→
682→        if !status.is_success() {
683→            return Ok(ProviderSnapshot {
684→                provider: "codex".into(),
685→                display_name: "Codex CLI".into(),
686→                primary_pct: None,
687→                secondary_pct: None,
688→                primary_label: Some("session".into()),
689→                secondary_label: Some("weekly".into()),
690→                tokens_used: None,
691→                cost_usd: None,
692→                reset_at: None,
693→                source: "oauth".into(),
694→                error: Some(format!("API returned HTTP {status}")),
695→            });
696→        }
697→
698→        let body = match resp.text().await {
699→            Ok(t) => t,
700→            Err(e) => {
701→                return Ok(ProviderSnapshot {
702→                    provider: "codex".into(),
703→                    display_name: "Codex CLI".into(),
704→                    primary_pct: None,
705→                    secondary_pct: None,
706→                    primary_label: Some("session".into()),
707→                    secondary_label: Some("weekly".into()),
708→                    tokens_used: None,
709→                    cost_usd: None,
710→                    reset_at: None,
711→                    source: "oauth".into(),
712→                    error: Some(format!("failed to read response body: {e}")),
713→                });
714→            }
