631→    /// Inner async function for the PTY exchange with the gemini process.
632→    /// Separated from `fetch_via_pty` so the timeout wrapper stays clean.
633→    async fn pty_exchange() -> anyhow::Result<ProviderSnapshot> {
634→        let mut child = tokio::process::Command::new("gemini")
635→            .stdin(std::process::Stdio::piped())
636→            .stdout(std::process::Stdio::piped())
637→            .stderr(std::process::Stdio::null())
638→            .kill_on_drop(true)
639→            .spawn()
640→            .context("failed to spawn `gemini` for PTY fallback")?;
641→
642→        let stdin = child
643→            .stdin
644→            .take()
645→            .context("no stdin on gemini PTY process")?;
646→        let stdout = child
647→            .stdout
648→            .take()
649→            .context("no stdout on gemini PTY process")?;
650→
651→        let mut writer = tokio::io::BufWriter::new(stdin);
652→        let mut reader = BufReader::new(stdout);
653→
654→        // Send /stats model command.
655→        writer
656→            .write_all(b"/stats model\n")
657→            .await
658→            .context("write /stats model")?;
659→        writer.flush().await.context("flush /stats model")?;
660→
661→        // Give the process a moment to produce output.
662→        tokio::time::sleep(Duration::from_millis(500)).await;
663→
664→        // Read all available output (up to 8KB).
665→        let mut output = String::new();
666→        let mut buf = [0u8; 4096];
667→        loop {
668→            match tokio::time::timeout(Duration::from_millis(500), reader.read(&mut buf)).await {
669→                Ok(Ok(0)) => break, // EOF
670→                Ok(Ok(n)) => output.push_str(&String::from_utf8_lossy(&buf[..n])),
671→                Ok(Err(_)) => break, // read error
672→                Err(_) => break,     // timeout — no more data
673→            }
674→        }
675→
676→        // Kill the child process.
677→        let _ = child.kill().await;
678→
679→        Ok(Self::parse_pty_output(&output))
680→    }
681→}
