683→#[async_trait::async_trait]
684→impl Provider for GeminiProvider {
685→    fn name(&self) -> &str {
686→        "gemini"
687→    }
688→
689→    /// Returns `true` if `~/.gemini/oauth_creds.json` exists OR `gemini`
690→    /// binary is on PATH.
691→    fn detect(&self) -> bool {
692→        Self::has_credentials_file() || Self::binary_on_path()
693→    }
694→
695→    /// Fetch current quota/usage from the Gemini API, falling back to PTY
696→    /// if OAuth fails.
697→    ///
698→    /// Flow: read credentials → extract OAuth client → refresh token →
699→    /// call loadCodeAssist (best-effort) → call retrieveUserQuota → parse.
700→    /// If any OAuth step fails, falls back to PTY via `gemini /stats model`.
701→    async fn fetch(&self) -> anyhow::Result<ProviderSnapshot> {
702→        let creds = match Self::read_credentials() {
703→            Ok(c) => c,
704→            Err(_) => {
705→                // No OAuth credentials — try PTY fallback.
706→                return Self::fetch_via_pty().await;
707→            }
708→        };
709→
710→        // Extract OAuth client info from the gemini npm package.
711→        let client_info = match Self::extract_oauth_client() {
712→            Some(info) => info,
713→            None => {
714→                // Cannot locate OAuth client — try PTY fallback.
715→                return Self::fetch_via_pty().await;
716→            }
717→        };
718→
719→        // Refresh token if expired.
720→        let access_token = match Self::refresh_token_if_expired(&creds, &client_info).await {
721→            Ok(t) => t,
722→            Err(_) => {
723→                // Token refresh failed — try PTY fallback.
724→                return Self::fetch_via_pty().await;
725→            }
726→        };
727→
728→        let client = reqwest::Client::new();
729→
730→        // Step 1: loadCodeAssist — best-effort to get cloudaicompanionProject.
731→        // If this fails, we pass an empty string to retrieveUserQuota.
732→        let project = Self::load_code_assist(&client, &access_token)
733→            .await
734→            .unwrap_or_default();
735→
736→        // Step 2: retrieveUserQuota — fetch the actual quota entries.
737→        let entries = match Self::retrieve_user_quota(&client, &access_token, &project).await {
738→            Ok(e) => e,
739→            Err(_) => {
740→                // Quota API failed — try PTY fallback.
741→                return Self::fetch_via_pty().await;
742→            }
743→        };
744→
745→        // Step 3: Parse the entries into a ProviderSnapshot.
746→        Ok(Self::parse_quota_response(&entries))
747→    }
748→}
