    56→fn validate_provider(name: &str, p: &AdapterConfig) -> anyhow::Result<()> {
    57→    if name.trim().is_empty() {
    58→        anyhow::bail!("provider name cannot be empty");
    59→    }
    60→    if p.command.trim().is_empty() {
    61→        anyhow::bail!("provider '{}': command/adapter cannot be empty", name);
    62→    }
    63→    Ok(())
