   143→pub fn rotate_provider_chain(meta: &mut Meta) {
   144→    if meta.provider_chain.len() <= 1 {
   145→        return;
   146→    }
   147→    let first = meta.provider_chain.remove(0);
   148→    meta.provider_chain.push(first);
