   151→pub fn select_provider(
   152→    cards_dir: &Path,
   153→    meta: Option<&mut Meta>,
   154→    stage: &str,
   155→) -> anyhow::Result<Option<ProviderSelection>> {
   156→    let pf = read_providers(cards_dir)?;
   157→    let now = Utc::now().timestamp();
   158→
   159→    let avoid_provider = if stage == "qa" {
   160→        meta.as_ref()
   161→            .and_then(|m| m.stages.get("implement"))
   162→            .and_then(|r| r.provider.clone())
   163→    } else {
   164→        None
   165→    };
   166→
   167→    let chain: Vec<String> = match meta {
   168→        Some(m) => {
   169→            if m.provider_chain.is_empty() {
   170→                m.provider_chain = vec!["mock".to_string(), "mock2".to_string()];
   171→            }
   172→            m.provider_chain.clone()
   173→        }
   174→        None => vec!["mock".to_string(), "mock2".to_string()],
   175→    };
   176→
   177→    let mut fallback: Option<ProviderSelection> = None;
   178→    for name in chain {
   179→        let Some(p) = pf.providers.get(&name) else {
   180→            continue;
   181→        };
   182→        if let Some(until) = p.cooldown_until_epoch_s {
   183→            if until > now {
   184→                continue;
   185→            }
   186→        }
   187→
   188→        if let Some(ref avoid) = avoid_provider {
   189→            if &name == avoid {
   190→                if fallback.is_none() {
   191→                    fallback = Some((
   192→                        name,
   193→                        p.command.clone(),
   194→                        p.rate_limit_exit,
   195→                        p.env.clone(),
   196→                        p.model.clone(),
   197→                    ));
   198→                }
   199→                continue;
   200→            }
   201→        }
   202→
   203→        return Ok(Some((
   204→            name,
   205→            p.command.clone(),
   206→            p.rate_limit_exit,
   207→            p.env.clone(),
   208→            p.model.clone(),
   209→        )));
   210→    }
   211→
   212→    Ok(fallback)
   213→}
   214→
   215→pub fn set_provider_cooldown(
   216→    cards_dir: &Path,
   217→    provider: &str,
   218→    cooldown_s: i64,
   219→) -> anyhow::Result<()> {
   220→    let mut pf = read_providers(cards_dir)?;
   221→    let now = Utc::now().timestamp();
   222→    if let Some(p) = pf.providers.get_mut(provider) {
   223→        p.cooldown_until_epoch_s = Some(now + cooldown_s);
   224→    }
   225→    write_providers(cards_dir, &pf)?;
   226→    Ok(())
   227→}
