    57→fn validate_provider(name: &str, p: &AdapterConfig) -> anyhow::Result<()> {
    58→    if name.trim().is_empty() {
    59→        anyhow::bail!("provider name cannot be empty");
    60→    }
    61→    if p.command.trim().is_empty() {
    62→        anyhow::bail!("provider '{}': command/adapter cannot be empty", name);
    63→    }
    64→    Ok(())
    65→}
