    67→fn providers_path(cards_dir: &Path) -> PathBuf {
    68→    cards_dir.join("providers.json")
    69→}
    70→
    71→pub fn read_providers(cards_dir: &Path) -> anyhow::Result<ProvidersFile> {
    72→    let p = providers_path(cards_dir);
    73→    if !p.exists() {
    74→        return Ok(ProvidersFile::default());
    75→    }
    76→    let bytes = fs::read(p)?;
    77→    let pf: ProvidersFile = serde_json::from_slice(&bytes)?;
    78→    for (name, provider) in &pf.providers {
    79→        validate_provider(name, provider)?;
    80→    }
    81→    Ok(pf)
    82→}
    83→
    84→pub fn write_providers(cards_dir: &Path, pf: &ProvidersFile) -> anyhow::Result<()> {
    85→    for (name, provider) in &pf.providers {
    86→        validate_provider(name, provider)?;
    87→    }
    88→    let bytes = serde_json::to_vec_pretty(pf)?;
    89→
    90→    let target = providers_path(cards_dir);
    91→    let tmp = target.with_extension("json.tmp");
    92→
    93→    fs::write(&tmp, &bytes)?;
    94→    fs::rename(&tmp, &target)?;
    95→
    96→    Ok(())
    97→}
