    99→pub fn seed_providers(cards_dir: &Path) -> anyhow::Result<()> {
   100→    let p = providers_path(cards_dir);
   101→    if p.exists() {
   102→        return Ok(());
   103→    }
   104→
   105→    let mut pf = ProvidersFile {
   106→        default_provider: Some("mock".to_string()),
   107→        ..Default::default()
   108→    };
   109→    pf.providers.insert(
   110→        "mock".to_string(),
   111→        AdapterConfig {
   112→            command: "adapters/mock.nu".to_string(),
   113→            rate_limit_exit: 75,
   114→            cooldown_until_epoch_s: None,
   115→            model: None,
   116→            env: Default::default(),
   117→            probe: true,
   118→        },
   119→    );
   120→    pf.providers.insert(
   121→        "mock2".to_string(),
   122→        AdapterConfig {
   123→            command: "adapters/mock.nu".to_string(),
   124→            rate_limit_exit: 75,
