   135→pub fn ensure_mock_provider_command(cards_dir: &Path, adapter: &str) -> anyhow::Result<()> {
   136→    let mut pf = read_providers(cards_dir)?;
   137→    if let Some(p) = pf.providers.get_mut("mock") {
   138→        p.command = adapter.to_string();
   139→    }
   140→    write_providers(cards_dir, &pf)?;
   141→    Ok(())
   142→}
