   152→pub fn select_provider(
   153→    cards_dir: &Path,
   154→    meta: Option<&mut Meta>,
   155→    stage: &str,
   156→) -> anyhow::Result<Option<ProviderSelection>> {
   157→    let pf = read_providers(cards_dir)?;
   158→    let now = Utc::now().timestamp();
   159→
   160→    let avoid_provider = if stage == "qa" {
   161→        meta.as_ref()
   162→            .and_then(|m| m.stages.get("implement"))
   163→            .and_then(|r| r.provider.clone())
   164→    } else {
   165→        None
   166→    };
   167→
   168→    let chain: Vec<String> = match meta {
   169→        Some(m) => {
   170→            if m.provider_chain.is_empty() {
   171→                m.provider_chain = vec!["mock".to_string(), "mock2".to_string()];
   172→            }
   173→            m.provider_chain.clone()
   174→        }
   175→        None => vec!["mock".to_string(), "mock2".to_string()],
   176→    };
   177→
   178→    let mut fallback: Option<ProviderSelection> = None;
   179→    for name in chain {
   180→        let Some(p) = pf.providers.get(&name) else {
   181→            continue;
   182→        };
   183→        if let Some(until) = p.cooldown_until_epoch_s {
   184→            if until > now {
   185→                continue;
   186→            }
   187→        }
   188→
   189→        if let Some(ref avoid) = avoid_provider {
   190→            if &name == avoid {
   191→                if fallback.is_none() {
   192→                    fallback = Some((
   193→                        name,
   194→                        p.command.clone(),
   195→                        p.rate_limit_exit,
   196→                        p.env.clone(),
   197→                        p.model.clone(),
   198→                    ));
   199→                }
   200→                continue;
   201→            }
   202→        }
   203→
   204→        return Ok(Some((
   205→            name,
   206→            p.command.clone(),
   207→            p.rate_limit_exit,
   208→            p.env.clone(),
   209→            p.model.clone(),
   210→        )));
   211→    }
   212→
   213→    Ok(fallback)
   214→}
