   216→pub fn set_provider_cooldown(
   217→    cards_dir: &Path,
   218→    provider: &str,
   219→    cooldown_s: i64,
   220→) -> anyhow::Result<()> {
   221→    let mut pf = read_providers(cards_dir)?;
   222→    let now = Utc::now().timestamp();
   223→    if let Some(p) = pf.providers.get_mut(provider) {
   224→        p.cooldown_until_epoch_s = Some(now + cooldown_s);
   225→    }
   226→    write_providers(cards_dir, &pf)?;
   227→    Ok(())
   228→}
